diff --git a/llvm/lib/Analysis/ConstantFolding.cpp b/llvm/lib/Analysis/ConstantFolding.cpp
index 88db315ffd0b..bcdaca3cdb2c 100644
--- a/llvm/lib/Analysis/ConstantFolding.cpp
+++ b/llvm/lib/Analysis/ConstantFolding.cpp
@@ -1177,6 +1177,14 @@ Constant *llvm::ConstantFoldCompareInstOperands(
     unsigned IntPredicate, Constant *Ops0, Constant *Ops1, const DataLayout &DL,
     const TargetLibraryInfo *TLI, const Instruction *I) {
   CmpInst::Predicate Predicate = (CmpInst::Predicate)IntPredicate;
+
+  // Do not fold if the denormal-fp-math is dynamic, because the result of
+  // the comparison may depend on the dynamic value of the fpcr register.
+  if (CmpInst::isFPPredicate(Predicate) && I) {
+    const DenormalMode Mode = I->getFPMathMode().getDenormalMode();
+    if (Mode.isDynamic())
+      return nullptr;
+  }
   // fold: icmp (inttoptr x), null         -> icmp x, 0
   // fold: icmp null, (inttoptr x)         -> icmp 0, x
   // fold: icmp (ptrtoint x), 0            -> icmp x, null
